import{_ as t,o,c as a,a2 as r}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"Logs & Containers","description":"","frontmatter":{},"headers":[],"relativePath":"app/logs-containers.md","filePath":"app/logs-containers.md"}'),n={name:"app/logs-containers.md"};function i(s,e,l,p,h,d){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="logs-containers" tabindex="-1">Logs &amp; Containers <a class="header-anchor" href="#logs-containers" aria-label="Permalink to &quot;Logs &amp; Containers&quot;">​</a></h1><p>These views give you visibility into a running <a href="/app/environments">environment</a>: which containers are up, what state they are in, and what the build and deploy processes are doing — in real time and from history.</p><h2 id="containers" tabindex="-1">Containers <a class="header-anchor" href="#containers" aria-label="Permalink to &quot;Containers&quot;">​</a></h2><p>The <strong>Containers</strong> view lists the containers that make up the active environment — the application container(s), any <a href="/app/services">service</a> containers, <a href="/app/workers">worker</a> containers, and the <a href="/app/cronjobs">cron</a> sidecar. Each row shows the container&#39;s live status (running, starting, restarting, stopped, paused).</p><p>Status is polled from the VPS over SSH and refreshes automatically, so the page reflects the current state of the environment without a manual reload.</p><h2 id="build-deploy-logs" tabindex="-1">Build &amp; deploy logs <a class="header-anchor" href="#build-deploy-logs" aria-label="Permalink to &quot;Build &amp; deploy logs&quot;">​</a></h2><p>The <strong>Logs</strong> view streams the output of the build and deploy pipeline:</p><ul><li><strong>Live tail</strong> — output appended in real time as a build or deployment runs.</li><li><strong>History</strong> — past log lines retained per project and branch, so you can review what happened on an earlier deployment.</li></ul><p>Log entries are stored with their branch and a type (for example build vs. deploy output), letting the view separate and replay the right stream for the selected environment.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Use the Logs view together with <a href="/app/deployments">Deployments</a> to debug a failed build — the deployment record tells you <em>that</em> it failed; the logs tell you <em>why</em>.</p></div><h2 id="configuration-view" tabindex="-1">Configuration view <a class="header-anchor" href="#configuration-view" aria-label="Permalink to &quot;Configuration view&quot;">​</a></h2><p>The <strong>Configuration</strong> view shows the live, fully resolved configuration that Tragwerk derived from <code>.tragwerk/config.xml</code> for the current environment. It brings together, in one place:</p><ul><li>Runtime and <strong>PHP version</strong></li><li><strong>Web server</strong> settings</li><li><a href="/app/workers">Workers</a></li><li><strong>Mounts</strong> and their current on-disk <strong>sizes</strong></li><li><a href="/app/services">Services</a> with live per-service status</li><li><strong>Hooks</strong> (build / deploy / post-deploy)</li><li><strong>Routes</strong></li></ul><p>Mount sizes are computed on demand from the VPS, so you can see how much disk each persistent mount is consuming.</p><h2 id="example-workflow" tabindex="-1">Example workflow <a class="header-anchor" href="#example-workflow" aria-label="Permalink to &quot;Example workflow&quot;">​</a></h2><ol><li>Trigger a <a href="/app/deployments">deployment</a> (push, or redeploy from the UI).</li><li>Open <strong>Logs</strong> and watch the live tail until the build finishes.</li><li>Switch to <strong>Containers</strong> to confirm every container reports <strong>Running</strong>.</li><li>Open <strong>Configuration</strong> to verify the resolved PHP version, mounts, and routes match your config.</li></ol><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/app/environments">Environments</a></li><li><a href="/app/deployments">Deployments</a></li><li><a href="/app/services">Services</a></li><li><a href="/app/workers">Workers</a></li><li><a href="/app/cronjobs">Cron Jobs</a></li><li><a href="/config/overview">Configuration overview</a></li></ul>',18)])])}const g=t(n,[["render",i]]);export{u as __pageData,g as default};
